  $.adminDateFilter.innerHTML = ['<option value="">Todas as datas</option>']
    .concat(
      DELIVERY_DAYS.map((day) => `<option value="${day.key}">${escapeHtml(`${day.label} - ${formatDateKey(day.key)}`)}</option>`)
    )
