function renderAll() {
  refreshCommercialSuggestionUI();
  const storeKey = getSelectedStore();
  const dayKeys = getSelectedDayKeys();
  const dayLabelText = getSelectedDayLabelText();

  $.selectedStoreName.textContent = getDisplayStoreName(storeKey);
  $.selectedDayName.textContent = dayLabelText;
  $.tableDayLabel.textContent = dayLabelText;
  $.responsavelInput.value = "";

  const productsToShow = [...new Set(dayKeys.flatMap((dayKey) => getRenderableProducts(storeKey, dayKey)))].sort((a, b) => a.localeCompare(b, "pt-BR"));
  const rows = productsToShow.map((product) => {
    const baseSale = dayKeys.reduce((sum, dayKey) => sum + Number(BASE_SALES[storeKey]?.[dayKey]?.[product] || 0), 0);
    const suggested = getCommercialSuggestionForProduct(storeKey, dayKeys, product);

    return {
      product,
      baseSale,
      suggested,
      storeSuggestion: "",
      observation: "",
    };
  });

  $.tableBody.innerHTML = rows.length
    ? rows
        .map((row) => `
      <tr data-product="${escapeHtml(row.product)}" data-base-sale="${row.baseSale}" data-suggested="${row.suggested}">
        <td>${escapeHtml(row.product)}</td>
        <td><span class="qty-base">${formatNumber(row.baseSale)}</span></td>
        <td><span class="qty-suggestion">${formatNumber(row.suggested)}</span></td>
        <td>
          <input
            class="cell-input"
            type="number"
            min="0"
            step="1"
            inputmode="numeric"
            value="${row.storeSuggestion}"
            data-role="store-suggestion"
          />
        </td>
        <td>
          <input
            class="cell-note"
            type="text"
            maxlength="160"
            placeholder="Observação da loja"
            value="${escapeAttribute(row.observation)}"
            data-role="observation"
          />
        </td>
      </tr>
    `)
        .join("")
    : `<tr><td colspan="5" class="admin-empty">Nenhum item disponível para a loja e dia selecionados na planilha base atual.</td></tr>`;

  bindRowEvents();
  updateTotals();
  clearStatus();
}

function bindRowEvents() {
  $.tableBody.querySelectorAll(".cell-input, .cell-note").forEach((field) => {
    field.addEventListener("input", () => {
      if (field.matches('[data-role="observation"]')) {
        field.classList.remove("is-required");
      }
      updateTotals();
      persistDraftFromScreen();
    });
  });
}

function updateTotals() {
  const rows = collectRowsFromScreen();
  const totalSold = rows.reduce((sum, row) => sum + row.baseSale, 0);
  const totalSoFolhas = rows.reduce((sum, row) => sum + row.suggested, 0);
  const totalStore = rows.reduce((sum, row) => sum + row.storeSuggestion, 0);

  $.totalSold.textContent = formatNumber(totalSold);
  $.totalSoFolhas.textContent = formatNumber(totalSoFolhas);
  $.totalStore.textContent = formatNumber(totalStore);
}

function collectRowsFromScreen() {
  return [...$.tableBody.querySelectorAll("tr")].filter((tr) => tr.querySelector('[data-role="store-suggestion"]')).map((tr) => {
    const product = tr.dataset.product;
    const baseSale = Number(tr.dataset.baseSale || 0);
    const suggested = Number(tr.dataset.suggested || getSoFolhasSuggestion(baseSale));
    const storeSuggestion = sanitizeInteger(tr.querySelector('[data-role="store-suggestion"]').value, 0);
    const observation = tr.querySelector('[data-role="observation"]').value.trim();

    return {
      product,
      baseSale,
      suggested,
      storeSuggestion,
      observation,
      justificationRequired: storeSuggestion !== suggested,
    };
  });
}

function persistDraftFromScreen() {
  if (!$.tableBody.children.length) return;

  const drafts = readJson(DRAFT_KEY);
  drafts[getSelectionKey()] = {
    loja: getSelectedStore(),
    dia: getSelectedDayValueForStorage(),
    responsavel: $.responsavelInput.value.trim(),
    percentualPorDia: Object.fromEntries(getSelectedDayKeys().map((dayKey) => [dayKey, getAdminPercentForDay(dayKey)])),
    items: collectRowsFromScreen(),
    updatedAt: new Date().toISOString(),
  };
  localStorage.setItem(DRAFT_KEY, JSON.stringify(drafts));
}

function getCurrentDraft() {
  return readJson(DRAFT_KEY)[getSelectionKey()] || null;
}

function getSavedSubmission() {
  return readJson(STORAGE_KEY)[getSelectionKey()] || null;
}

async function onSave() {
  const responsavel = $.responsavelInput.value.trim();
  if (!responsavel) {
    showStatus("Informe o nome de quem está preenchendo a sugestão.", true);
    $.responsavelInput.focus();
    return;
  }

  const items = collectRowsFromScreen();
  if (!items.length) {
    showStatus("Não há itens disponíveis da planilha base para salvar nesta loja e neste dia.", true);
    return;
  }

  if (!validateRequiredJustifications()) {
    return;
  }

  const payload = {
    loja: getSelectedStore(),
    lojaExibicao: getDisplayStoreName(getSelectedStore()),
    dia: getSelectedDayValueForStorage(),
    diaSemana: getDayLabel(getSelectedDayKey()),
    responsavel,
    percentualPorDia: Object.fromEntries(getSelectedDayKeys().map((dayKey) => [dayKey, getAdminPercentForDay(dayKey)])),
    totalVendido: items.reduce((sum, row) => sum + row.baseSale, 0),
    totalSoFolhas: items.reduce((sum, row) => sum + row.suggested, 0),
    totalLoja: items.reduce((sum, row) => sum + row.storeSuggestion, 0),
    items,
    updatedAt: new Date().toISOString(),
  };

  try {
    const saved = readJson(STORAGE_KEY);
    saved[getSelectionKey()] = payload;
    localStorage.setItem(STORAGE_KEY, JSON.stringify(saved));

    const drafts = readJson(DRAFT_KEY);
    delete drafts[getSelectionKey()];
    localStorage.setItem(DRAFT_KEY, JSON.stringify(drafts));

    let successMessage = "Sugestão salva com sucesso neste navegador.";

    if (cloud) {
      await cloud.save(getSelectionKey(), payload);
      successMessage = "Sugestão salva com sucesso na nuvem.";
    }

    $.responsavelInput.value = "";
    renderAll();
    refreshAdminSummary().catch(console.error);
    renderizarTabelaADM().catch(console.error);
    showStatus(successMessage);
  } catch (error) {
    console.error(error);
    showStatus("Não foi possível salvar a sugestão agora.", true);
  }
}

async function initCloud() {
  if (!FIREBASE_CONFIG) return;

  try {
    const [appModule, databaseModule] = await Promise.all([
      import("https://www.gstatic.com/firebasejs/10.12.5/firebase-app.js"),
      import("https://www.gstatic.com/firebasejs/10.12.5/firebase-database.js"),
    ]);

    const normalizedConfig = {
      ...FIREBASE_CONFIG,
      databaseURL: FIREBASE_CONFIG.databaseURL || `https://${FIREBASE_CONFIG.projectId}-default-rtdb.firebaseio.com`,
    };

    const app = appModule.initializeApp(normalizedConfig);
    const db = databaseModule.getDatabase(app);
    const submissionsRef = databaseModule.ref(db, REALTIME_DB_SUBMISSIONS_PATH);
    const adminRef = databaseModule.ref(db, REALTIME_DB_ADMIN_PATH);

    cloud = {
      submissionsCache: null,
      adminBaseCache: null,
      importedFilesCache: null,
      save: async (docId, payload) => {
        await databaseModule.set(
          databaseModule.child(submissionsRef, docId),
          {
            ...payload,
            id: docId,
            updatedAtServer: new Date().toISOString(),
          }
        );
      },
      listAll: async () => {
        if (Array.isArray(cloud?.submissionsCache)) {
          return cloud.submissionsCache;
        }
        const snapshot = await databaseModule.get(submissionsRef);
        const data = snapshot.exists() ? snapshot.val() : {};
        return Object.entries(data || {}).map(([id, value]) => ({
          id,
          ...(value || {}),
        }));
      },
      clearAll: async () => {
        await databaseModule.remove(submissionsRef);
      },
      deleteMany: async (docIds) => {
        await Promise.all((docIds || []).map((docId) => databaseModule.remove(databaseModule.child(submissionsRef, docId))));
      },
      saveAdminBase: async (base) => {
        await databaseModule.set(databaseModule.child(adminRef, 'base'), base || {});
      },
      loadAdminBase: async () => {
        if (cloud && cloud.adminBaseCache !== null) {
          return cloud.adminBaseCache;
        }
        const snapshot = await databaseModule.get(databaseModule.child(adminRef, 'base'));
        return snapshot.exists() ? snapshot.val() : null;
      },
      saveImportedFiles: async (files) => {
        await databaseModule.set(databaseModule.child(adminRef, 'importedFiles'), files || []);
      },
      saveAdminPercentages: async (config) => {
        await databaseModule.set(databaseModule.child(adminRef, 'percentuaisDia'), config || createDefaultAdminPercentages());
      },
      saveAdminDayLabels: async (config) => {
        await databaseModule.set(databaseModule.child(adminRef, 'labelsDia'), config || createDefaultAdminDayLabels());
      },
      loadImportedFiles: async () => {
        if (cloud && Array.isArray(cloud.importedFilesCache)) {
          return cloud.importedFilesCache;
        }
        const snapshot = await databaseModule.get(databaseModule.child(adminRef, 'importedFiles'));
        return snapshot.exists() ? snapshot.val() : [];
      },
      loadAdminPercentages: async () => {
        const snapshot = await databaseModule.get(databaseModule.child(adminRef, 'percentuaisDia'));
        return snapshot.exists() ? snapshot.val() : createDefaultAdminPercentages();
      },
      loadAdminDayLabels: async () => {
        const snapshot = await databaseModule.get(databaseModule.child(adminRef, 'labelsDia'));
        return snapshot.exists() ? snapshot.val() : createDefaultAdminDayLabels();
      },
      clearAdminState: async () => {
        await Promise.all([
          databaseModule.remove(databaseModule.child(adminRef, 'base')),
          databaseModule.remove(databaseModule.child(adminRef, 'importedFiles')),
          databaseModule.remove(databaseModule.child(adminRef, 'percentuaisDia')),
          databaseModule.remove(databaseModule.child(adminRef, 'labelsDia')),
        ]);
      },
      bindRealtime: () => {
        if (realtimeBindingsStarted) return;
        realtimeBindingsStarted = true;

        databaseModule.onValue(submissionsRef, (snapshot) => {
          const data = snapshot.exists() ? snapshot.val() : {};
          const list = Object.entries(data || {}).map(([id, value]) => ({
            id,
            ...(value || {}),
          }));
          cloud.submissionsCache = list;
          localStorage.setItem(STORAGE_KEY, JSON.stringify(data || {}));
          renderAll();
          refreshAdminSummary().catch(console.error);
          renderizarTabelaADM().catch(console.error);
        }, (error) => {
          console.error('Falha ao sincronizar sugestões em tempo real:', error);
        });

        databaseModule.onValue(databaseModule.child(adminRef, 'base'), (snapshot) => {
          const cloudBase = snapshot.exists() ? snapshot.val() : {};
          cloud.adminBaseCache = cloudBase;
          if (cloudBase && typeof cloudBase === 'object' && Object.keys(cloudBase).length) {
            DELIVERY_DAYS = buildDeliveryDaysFromBase(cloudBase);
            BASE_SALES = normalizeImportedBase(cloudBase);
            localStorage.setItem(ADMIN_BASE_KEY, JSON.stringify(cloudBase));
          } else {
            DELIVERY_DAYS = buildDeliveryDaysFromBase(ORIGINAL_BASE_SALES);
            BASE_SALES = normalizeImportedBase({});
            localStorage.removeItem(ADMIN_BASE_KEY);
          }
          refreshDeliveryDaysConfig();
          visibleProductsIndex = buildVisibleProductsIndex(BASE_SALES);
          populateFilters();
          populateAdminStoreFilter();
          populateAdminDateFilter();
          applyInitialSelection();
          renderAdminImportedFiles();
          renderAll();
          refreshAdminSummary().catch(console.error);
          renderizarTabelaADM().catch(console.error);
        }, (error) => {
          console.error('Falha ao sincronizar base da ADM em tempo real:', error);
        });

        databaseModule.onValue(databaseModule.child(adminRef, 'importedFiles'), (snapshot) => {
          const files = snapshot.exists() ? snapshot.val() : [];
          cloud.importedFilesCache = Array.isArray(files) ? files : [];
          localStorage.setItem(ADMIN_IMPORTED_FILES_KEY, JSON.stringify(cloud.importedFilesCache));
          renderAdminImportedFiles();
        }, (error) => {
          console.error('Falha ao sincronizar planilhas anexadas em tempo real:', error);
        });

        databaseModule.onValue(databaseModule.child(adminRef, 'percentuaisDia'), (snapshot) => {
          const config = snapshot.exists() ? snapshot.val() : createDefaultAdminPercentages();
          adminDayPercentages = normalizeAdminPercentages(config);
          localStorage.setItem(ADMIN_PERCENTAGES_KEY, JSON.stringify(adminDayPercentages));
          refreshDeliveryDaysConfig();
          renderAdminPercentageTable();
          refreshCommercialSuggestionUI();
          renderAll();
          refreshAdminSummary().catch(console.error);
          renderizarTabelaADM().catch(console.error);
        }, (error) => {
          console.error('Falha ao sincronizar percentuais da ADM em tempo real:', error);
        });

        databaseModule.onValue(databaseModule.child(adminRef, 'labelsDia'), (snapshot) => {
          const config = snapshot.exists() ? snapshot.val() : createDefaultAdminDayLabels();
          adminDayLabels = normalizeAdminDayLabels(config);
          localStorage.setItem(ADMIN_DAY_LABELS_KEY, JSON.stringify(adminDayLabels));
          refreshDeliveryDaysConfig();
          populateFilters();
          populateAdminDateFilter();
          renderAdminPercentageTable();
          renderAll();
          refreshAdminSummary().catch(console.error);
          renderizarTabelaADM().catch(console.error);
        }, (error) => {
          console.error('Falha ao sincronizar nomes dos dias da ADM em tempo real:', error);
        });
      },
    };

    cloud.bindRealtime();
  } catch (error) {
    console.error("Falha ao iniciar Firebase:", error);
    showStatus("O site abriu normalmente, mas a conexão com a nuvem não foi iniciada.", true);
  }
}

async function hydrateAdminStateFromCloud() {
  if (!cloud) return;

  try {
    const [cloudBase, cloudImportedFiles, cloudPercentages, cloudDayLabels] = await Promise.all([
      cloud.loadAdminBase?.(),
      cloud.loadImportedFiles?.(),
      cloud.loadAdminPercentages?.(),
      cloud.loadAdminDayLabels?.(),
    ]);

    if (cloudBase && typeof cloudBase === 'object' && Object.keys(cloudBase).length) {
      DELIVERY_DAYS = buildDeliveryDaysFromBase(cloudBase);
      BASE_SALES = normalizeImportedBase(cloudBase);
      visibleProductsIndex = buildVisibleProductsIndex(BASE_SALES);
      localStorage.setItem(ADMIN_BASE_KEY, JSON.stringify(cloudBase));
    }

    if (Array.isArray(cloudImportedFiles)) {
      localStorage.setItem(ADMIN_IMPORTED_FILES_KEY, JSON.stringify(cloudImportedFiles));
    }

    if (cloudPercentages && typeof cloudPercentages === 'object') {
      adminDayPercentages = normalizeAdminPercentages(cloudPercentages);
      localStorage.setItem(ADMIN_PERCENTAGES_KEY, JSON.stringify(adminDayPercentages));
    }

    renderAdminPercentageTable();
    refreshCommercialSuggestionUI();
  } catch (error) {
    console.error('Falha ao carregar a base da ADM da nuvem:', error);
  }
}

function getSoFolhasSuggestion(baseSale, dayKey = "") {
  const multiplier = 1 + (getAdminPercentForDay(dayKey) / 100);
  return Math.ceil(Number(baseSale || 0) * multiplier);
}

function getSelectionKey() {
  return `${slugify(getSelectedStore())}__${getSelectedDayKeys().join("+")}`;
}

function getSelectedStore() {
  return $.storeSelect.value;
}

function getSelectedDayKey() {
  return getSelectedDayKeys()[0] || $.daySelect.value;
}

function getSelectedDayKeys() {
  if (!$.daySelect) return [];
  const values = [...$.daySelect.selectedOptions].map((option) => option.value).filter(Boolean);
  if (values.length) return values;
  return $.daySelect.value ? [$.daySelect.value] : [];
}

function getSelectedDayValueForStorage() {
  const dayKeys = getSelectedDayKeys();
  return dayKeys.length > 1 ? dayKeys : (dayKeys[0] || "");
}

function getSelectedDayLabelText() {
  const labels = getSelectedDayKeys().map((dayKey) => getDayLabel(dayKey)).filter(Boolean);
  return labels.join(" + ") || "-";
}

function isMultiDayStore(storeKey) {
  const normalized = slugify(`${getDisplayStoreName(storeKey)} ${storeKey}`);
  return MULTI_DAY_STORE_MATCHES.some((term) => normalized.includes(term));
}

function syncDaySelectMode() {
  if (!$.daySelect) return;
  const currentValues = getSelectedDayKeys();
  const shouldBeMultiple = isMultiDayStore(getSelectedStore());
  $.daySelect.multiple = shouldBeMultiple;
  $.daySelect.size = shouldBeMultiple ? DELIVERY_DAYS.length : 1;

  [...$.daySelect.options].forEach((option) => {
    option.selected = shouldBeMultiple
      ? (currentValues.length ? currentValues.includes(option.value) : option === $.daySelect.options[0])
      : option.value === (currentValues[0] || option.value);
  });

  if (!shouldBeMultiple) {
    $.daySelect.value = currentValues[0] || $.daySelect.options[0]?.value || "";
  }
}

function getDayLabel(dayKey) {
  return getAdminDayLabel(dayKey) || DELIVERY_DAYS.find((day) => day.key === dayKey)?.label || "";
}

function formatDateKey(dayKey) {
  if (!dayKey) return "";
  const [year, month, day] = String(dayKey).split("-");
  if (!year || !month || !day) return String(dayKey);
  return `${day}/${month}/${year}`;
}

function ensureStoresWithoutReference(baseSales, displayNames) {
  STORES_WITHOUT_REFERENCE.forEach((storeName) => {
    displayNames[storeName] = storeName;
    if (!baseSales[storeName]) {
      baseSales[storeName] = createEmptyStoreBase();
    }
  });
}

function getDisplayStoreName(storeKey) {
  return STORE_DISPLAY_NAMES[storeKey] || storeKey;
}

function updateUrlParams() {
  const params = new URLSearchParams(window.location.search);
  params.set("store", slugify(getSelectedStore()));
  params.set("day", getSelectedDayKey());
  const nextUrl = `${window.location.pathname}?${params.toString()}`;
  window.history.replaceState({}, "", nextUrl);
}

function findStoreFromParam(rawValue) {
  if (!rawValue) return null;
  const target = slugify(rawValue);
  return Object.keys(BASE_SALES).find((store) =>
    slugify(store) === target || slugify(getDisplayStoreName(store)) === target
  ) || null;
}

function findDayFromParam(rawValue) {
  if (!rawValue) return null;
  const target = slugify(rawValue);
  return DELIVERY_DAYS.find((day) =>
    day.key === rawValue ||
    slugify(day.label) === target
  )?.key || null;
}


function isAdminAuthenticated() {
  return sessionStorage.getItem(ADMIN_SESSION_KEY) === "1";
}

function showAdminLoginMessage(message, isError = false) {
  if (!$.adminLoginMessage) return;
  $.adminLoginMessage.textContent = message;
  $.adminLoginMessage.classList.toggle("is-error", Boolean(isError));
  $.adminLoginMessage.classList.toggle("is-success", !isError && Boolean(message));
}

function syncElementVisibility(element, isVisible, displayValue = "block") {
  if (!element) return;

  element.hidden = !isVisible;
  element.setAttribute("aria-hidden", String(!isVisible));
  element.style.display = isVisible ? displayValue : "none";
  element.style.visibility = isVisible ? "visible" : "hidden";
  element.style.opacity = isVisible ? "1" : "0";
  element.style.pointerEvents = isVisible ? "auto" : "none";

  if (isVisible) {
    element.removeAttribute("hidden");
  } else {
    element.setAttribute("hidden", "hidden");
  }
}

function syncAdminAuthUI() {
  const authenticated = isAdminAuthenticated();

  syncElementVisibility($.adminLoginCard, !authenticated, "block");
  syncElementVisibility($.adminContent, authenticated, "block");

  if (authenticated) {
    showAdminLoginMessage("");
    if ($.adminLoginInput) $.adminLoginInput.value = "";
    if ($.adminPasswordInput) $.adminPasswordInput.value = "";
  } else {
    switchAdminTab("import");
  }
}

function validarLoginADM() {
  const login = $.adminLoginInput?.value?.trim() || "";
  const password = $.adminPasswordInput?.value || "";

  if (login === ADMIN_LOGIN && password === ADMIN_PASSWORD) {
    sessionStorage.setItem(ADMIN_SESSION_KEY, "1");
    syncAdminAuthUI();
    switchAdminTab("import");
    refreshAdminSummary().catch(console.error);
    renderizarTabelaADM().catch(console.error);
    return;
  }

  showAdminLoginMessage("Credencial inválida.", true);
  $.adminPasswordInput?.focus();
}

function handleAdminLogin() {
  if (window.forceAdminLogin) {
    window.forceAdminLogin();
  }
  validarLoginADM();
}

function logoutAdmin() {
  sessionStorage.removeItem(ADMIN_SESSION_KEY);
  syncAdminAuthUI();
  showAdminLoginMessage("Acesso encerrado.");
}

function switchAdminTab(tab) {
  const activeTab = tab === "data" ? "data" : "import";
  const importActive = activeTab === "import";

  if ($.adminTabImport) {
    $.adminTabImport.classList.toggle("is-active", importActive);
    $.adminTabImport.setAttribute("aria-selected", String(importActive));
  }

  if ($.adminTabData) {
    $.adminTabData.classList.toggle("is-active", !importActive);
    $.adminTabData.setAttribute("aria-selected", String(!importActive));
  }

  syncElementVisibility($.adminImportSection, importActive, "block");
  syncElementVisibility($.adminDataSection, !importActive, "block");
}

function loadPersistedAdminBase() {
  const savedBase = readJson(ADMIN_BASE_KEY);
  if (savedBase && typeof savedBase === "object" && Object.keys(savedBase).length) {
    BASE_SALES = normalizeImportedBase(savedBase);
  } else {
    BASE_SALES = normalizeImportedBase({});
  }

  visibleProductsIndex = buildVisibleProductsIndex(BASE_SALES);
}

function setAdminModalState(isOpen) {
  if (!$.adminModal) return;

  syncElementVisibility($.adminModal, isOpen, "grid");

  if (isOpen) {
    document.body.classList.add("modal-open");
  } else {
    document.body.classList.remove("modal-open");
  }
}

function abrirADM() {
  if (!$.adminModal) return;

  if (window.forceOpenAdmin) {
    window.forceOpenAdmin();
  }

  setAdminModalState(true);
  syncAdminAuthUI();

  if (isAdminAuthenticated()) {
    hydrateAdminStateFromCloud()
      .then(() => {
        populateFilters();
        populateAdminStoreFilter();
        populateAdminDateFilter();
        renderAdminImportedFiles();
        renderAdminPercentageTable();
        renderAll();
        return refreshAdminSummary();
      })
      .then(() => renderizarTabelaADM())
      .catch((error) => {
        console.error(error);
        showStatus("A ADM foi aberta, mas os dados não puderam ser atualizados agora.", true);
      });
    return;
  }

  showAdminLoginMessage("");
  if ($.adminLoginInput) $.adminLoginInput.value = "";
  if ($.adminPasswordInput) $.adminPasswordInput.value = "";
  $.adminLoginInput?.focus();
}

function fecharADM() {
  if (!$.adminModal) return;

  if (window.forceCloseAdmin) {
    window.forceCloseAdmin();
  }

  setAdminModalState(false);
  showAdminLoginMessage("");

  if ($.adminPasswordInput) {
    $.adminPasswordInput.value = "";
  }

  $.adminToggle?.focus();
}

function openAdminModal() {
  abrirADM();
}

function closeAdminModal() {
  fecharADM();
}

window.openAdminModal = openAdminModal;
window.closeAdminModal = closeAdminModal;
window.handleAdminLogin = handleAdminLogin;
window.onAdminImport = onAdminImport;
window.logoutAdminArea = logoutAdmin;
window.refreshAdminSummaryView = async () => {
  await refreshAdminSummary();
  await renderizarTabelaADM();
};
window.showAdminImportTab = () => handleAdminTabClick("import");
window.showAdminDataTab = async () => {
  handleAdminTabClick("data");
  if (isAdminAuthenticated()) {
    await renderizarTabelaADM();
  }
};
window.exportAdminSummary = exportarResumoADM;
window.exportAdminFilledData = exportarDadosPreenchidosADM;
window.saveAdminCommercialPercentages = saveAdminPercentages;

async function processarImportacaoBase() {
  const file = $.adminFileInput?.files?.[0];
  if (!file) {
    showStatus("Selecione uma planilha no botão ADM para importar a base.", true);
    return;
  }

  try {
    const importedBase = await parseBaseSpreadsheet(file);

    if (!Object.keys(importedBase).length) {
      throw new Error("A planilha importada não retornou dados válidos.");
    }

    const currentStore = getSelectedStore();
    const currentDay = getSelectedDayKey();

    DELIVERY_DAYS = buildDeliveryDaysFromBase(importedBase);
    adminDayPercentages = normalizeAdminPercentages(adminDayPercentages);
    adminDayLabels = normalizeAdminDayLabels(adminDayLabels);
    const normalizedBase = normalizeImportedBase(importedBase);

    await clearAllSubmissionData();

    BASE_SALES = normalizedBase;
    refreshDeliveryDaysConfig();
    visibleProductsIndex = buildVisibleProductsIndex(normalizedBase);
    const importedFilesMeta = [buildImportedFileMeta(file, normalizedBase)];
    localStorage.setItem(ADMIN_BASE_KEY, JSON.stringify(normalizedBase));
    localStorage.setItem(ADMIN_IMPORTED_FILES_KEY, JSON.stringify(importedFilesMeta));

    if (cloud?.saveAdminBase) {
      await cloud.saveAdminBase(normalizedBase);
    }

    if (cloud?.saveImportedFiles) {
      await cloud.saveImportedFiles(importedFilesMeta);
    }

    populateFilters();
    populateAdminStoreFilter();
    populateAdminDateFilter();
    renderAdminImportedFiles();

    if ([...$.storeSelect.options].some((option) => option.value === currentStore)) {
      $.storeSelect.value = currentStore;
    } else if ($.storeSelect.options.length) {
      $.storeSelect.value = $.storeSelect.options[0].value;
    }

    if ([...$.daySelect.options].some((option) => option.value === currentDay)) {
      $.daySelect.value = currentDay;
    } else if ($.daySelect.options.length) {
      $.daySelect.value = $.daySelect.options[0].value;
    }

    renderAll();
    await refreshAdminSummary();
    await renderizarTabelaADM();
    showStatus("Base importada com sucesso pelo ADM. A planilha anterior foi substituída.");
  } catch (error) {
    console.error(error);
    showStatus(error?.message || "Não foi possível importar a planilha base no ADM.", true);
  }
}

async function onAdminImport() {
  await processarImportacaoBase();
}

async function parseBaseSpreadsheet(file) {
  if (!window.XLSX) {
    throw new Error("Biblioteca XLSX não carregada.");
  }

  const buffer = await file.arrayBuffer();
  const workbook = window.XLSX.read(buffer, {
    type: "array",
    cellDates: true,
  });

  const rows = getSpreadsheetRows(workbook);

  if (!rows.length) {
    throw new Error("A planilha está vazia.");
  }

  const columns = Object.keys(rows[0]);
  const storeColumn = pickSpreadsheetColumn(columns, ["filial", "loja", "nome loja", "desc filial", "filial destino"], ["Filial", "Loja", "Nome Loja"]);
  const productColumn = pickSpreadsheetColumn(columns, ["produto", "item", "descricao", "descricao produto", "desc produto"], ["Produto", "Item", "Descrição", "Descricao"]);
  const qtyColumn = pickSpreadsheetColumn(columns, ["qtd faturada", "quantidade faturada", "qtd", "qtde", "quantidade", "faturado"], ["Qtd. Faturada", "Quantidade Faturada", "Qtd Faturada", "Qtde"]);
  const dateColumn = pickSpreadsheetColumn(columns, ["date", "data", "data faturamento", "dt faturamento"], ["Date", "Data", "Data Faturamento"]);

  if (!storeColumn || !productColumn || !qtyColumn || !dateColumn) {
    throw new Error("As colunas esperadas não foram encontradas na planilha.");
  }

  const importedBase = {};

  rows.forEach((row) => {
    const rawStore = String(row[storeColumn] || "").trim();
    const rawProduct = String(row[productColumn] || "").trim();
    const dayKey = parseSpreadsheetDate(row[dateColumn]);
    const quantity = sanitizeInteger(row[qtyColumn], 0);

    if (!rawStore || !rawProduct || !dayKey) return;

    const matchedProduct = matchProduct(rawProduct);
    if (!matchedProduct) return;

    const storeKey = findStoreFromParam(rawStore) || findStoreByDisplayName(rawStore) || rawStore;

    importedBase[storeKey] ??= {};
    importedBase[storeKey][dayKey] ??= {};

    const currentValue = Number(importedBase[storeKey][dayKey][matchedProduct] || 0);
    importedBase[storeKey][dayKey][matchedProduct] = currentValue + quantity;
  });

  return importedBase;
}

function getSpreadsheetRows(workbook) {
  for (const sheetName of workbook.SheetNames) {
    const sheet = workbook.Sheets[sheetName];
    const rows = window.XLSX.utils.sheet_to_json(sheet, {
      defval: "",
      raw: true,
    });

    if (rows.length) return rows;
  }

  return [];
}

function pickSpreadsheetColumn(columns, aliases, preferredColumns = []) {
  const normalizedColumns = columns.map((column) => ({
    original: column,
    normalized: slugify(column).replaceAll("-", " "),
  }));

  const exactPreferred = preferredColumns.find((preferred) =>
    normalizedColumns.some((column) => column.normalized === slugify(preferred).replaceAll("-", " "))
  );

  if (exactPreferred) {
    return normalizedColumns.find((column) =>
      column.normalized === slugify(exactPreferred).replaceAll("-", " ")
    )?.original || null;
  }

  const exactAliasMatch = normalizedColumns.find((column) =>
    aliases.some((alias) => column.normalized === slugify(alias).replaceAll("-", " "))
  );

  if (exactAliasMatch) {
    return exactAliasMatch.original;
  }

  return normalizedColumns.find((column) =>
    aliases.some((alias) => column.normalized.includes(slugify(alias).replaceAll("-", " ")))
  )?.original || null;
}

function parseSpreadsheetDate(value) {
  if (!value && value !== 0) return null;

  if (value instanceof Date && !Number.isNaN(value.getTime())) {
    return [
      value.getFullYear(),
      String(value.getMonth() + 1).padStart(2, "0"),
      String(value.getDate()).padStart(2, "0"),
    ].join("-");
  }

  if (typeof value === "number" && window.XLSX?.SSF?.parse_date_code) {
    const parsed = window.XLSX.SSF.parse_date_code(value);
    if (parsed) {
      return [
        parsed.y,
        String(parsed.m).padStart(2, "0"),
        String(parsed.d).padStart(2, "0"),
      ].join("-");
    }
  }

  const text = String(value).trim();
  if (!text) return null;

  const isoMatch = text.match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (isoMatch) {
    return `${isoMatch[1]}-${isoMatch[2]}-${isoMatch[3]}`;
  }

  const brMatch = text.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (brMatch) {
    return `${brMatch[3]}-${brMatch[2]}-${brMatch[1]}`;
  }

  const brDashMatch = text.match(/^(\d{2})-(\d{2})-(\d{4})$/);
  if (brDashMatch) {
    return `${brDashMatch[3]}-${brDashMatch[2]}-${brDashMatch[1]}`;
  }

  const parsedDate = new Date(text);
  if (!Number.isNaN(parsedDate.getTime())) {
    return [
      parsedDate.getFullYear(),
      String(parsedDate.getMonth() + 1).padStart(2, "0"),
      String(parsedDate.getDate()).padStart(2, "0"),
    ].join("-");
  }

  return null;
}

function matchProduct(rawProduct) {
  const target = slugify(rawProduct);

  const exactMatch = PRODUCT_ORDER.find((product) => slugify(product) === target);
  if (exactMatch) return exactMatch;

  return PRODUCT_ORDER.find((product) => {
    const normalizedProduct = slugify(product);
    return target.includes(normalizedProduct) || normalizedProduct.includes(target);
  }) || null;
}

function createEmptyStoreBase() {
  const days = {};

  DELIVERY_DAYS.forEach((day) => {
    days[day.key] = {};
    PRODUCT_ORDER.forEach((product) => {
      days[day.key][product] = 0;
    });
  });

  return days;
}

function normalizeImportedBase(importedBase) {
  const normalized = {};

  Object.keys(ORIGINAL_BASE_SALES).forEach((storeKey) => {
    normalized[storeKey] = createEmptyStoreBase();
  });

  Object.entries(importedBase || {}).forEach(([storeKey, days]) => {
    normalized[storeKey] ??= createEmptyStoreBase();

    Object.entries(days || {}).forEach(([dayKey, products]) => {
      if (!DELIVERY_DAYS.some((day) => day.key === dayKey)) return;

      normalized[storeKey][dayKey] ??= {};

      PRODUCT_ORDER.forEach((product) => {
        const value = Number(products?.[product] || 0);
        normalized[storeKey][dayKey][product] = Number.isFinite(value) ? value : 0;
      });
    });
  });

  return normalized;
}

function findStoreByDisplayName(rawStore) {
  const target = slugify(rawStore);
  return Object.keys(STORE_DISPLAY_NAMES).find((storeKey) =>
    slugify(getDisplayStoreName(storeKey)) === target
  ) || null;
}

function getRenderableProducts(storeKey, dayKey) {
  const indexedProducts = visibleProductsIndex?.[storeKey]?.[dayKey];
  if (Array.isArray(indexedProducts) && indexedProducts.length) {
    return [...indexedProducts].sort((a, b) => a.localeCompare(b, "pt-BR"));
  }

  if (STORES_WITHOUT_REFERENCE.includes(storeKey)) {
    return [...SORTED_PRODUCT_ORDER];
  }

  return SORTED_PRODUCT_ORDER.filter((product) => Number(BASE_SALES?.[storeKey]?.[dayKey]?.[product] || 0) > 0);
}

function buildVisibleProductsIndex(baseSales) {
  const index = {};

  Object.keys(baseSales || {}).forEach((storeKey) => {
    index[storeKey] = {};
    DELIVERY_DAYS.forEach((day) => {
      index[storeKey][day.key] = SORTED_PRODUCT_ORDER.filter((product) => Number(baseSales?.[storeKey]?.[day.key]?.[product] || 0) > 0);
    });
  });

  return index;
}

function buildImportedFileMeta(file, normalizedBase) {
  const storeCount = Object.keys(normalizedBase || {}).filter((storeKey) =>
    DELIVERY_DAYS.some((day) => PRODUCT_ORDER.some((product) => Number(normalizedBase?.[storeKey]?.[day.key]?.[product] || 0) > 0))
  ).length;

  const productSet = new Set();
  Object.keys(normalizedBase || {}).forEach((storeKey) => {
    DELIVERY_DAYS.forEach((day) => {
      PRODUCT_ORDER.forEach((product) => {
        if (Number(normalizedBase?.[storeKey]?.[day.key]?.[product] || 0) > 0) {
          productSet.add(product);
        }
      });
    });
  });

  return {
    id: `base_${Date.now()}`,
    name: file?.name || "Planilha base",
    importedAt: new Date().toISOString(),
    storeCount,
    productCount: productSet.size,
  };
}

function getImportedFilesList() {
  const raw = readJson(ADMIN_IMPORTED_FILES_KEY);
  return Array.isArray(raw) ? raw : [];
}

function renderAdminImportedFiles() {
  if (!$.adminFilesBody || !$.adminFilesMeta) return;

  const files = getImportedFilesList();
  $.adminFilesMeta.textContent = files.length ? `${files.length} planilha ativa` : "Nenhuma planilha ativa";
  $.adminFilesBody.innerHTML = files.length
    ? files.map((file) => `
        <tr>
          <td>${escapeHtml(file.name || "Planilha base")}</td>
          <td>${escapeHtml(formatDateTime(file.importedAt))}</td>
          <td>${formatNumber(file.storeCount || 0)}</td>
          <td>${formatNumber(file.productCount || 0)}</td>
          <td><button class="admin-secondary-button" type="button" data-role="delete-imported-file">Excluir planilha</button></td>
        </tr>
      `).join("")
    : `<tr><td colspan="5" class="admin-empty">Nenhuma planilha anexada no momento.</td></tr>`;
}

async function clearAllSubmissionData() {
  localStorage.removeItem(STORAGE_KEY);
  localStorage.removeItem(DRAFT_KEY);

  if (cloud?.clearAll) {
    await cloud.clearAll();
  }
}

async function handleDeleteImportedFile() {
  if (!isAdminAuthenticated()) {
    showAdminLoginMessage("Faça o login da ADM para excluir a planilha.", true);
    syncAdminAuthUI();
    return;
  }

  if (!window.confirm("Excluir a planilha ativa e apagar todos os dados preenchidos ligados a ela?")) {
    return;
  }

  try {
    await clearAllSubmissionData();
    if (cloud?.clearAdminState) {
      await cloud.clearAdminState();
    }
    DELIVERY_DAYS = buildDeliveryDaysFromBase(ORIGINAL_BASE_SALES);
    BASE_SALES = normalizeImportedBase({});
    visibleProductsIndex = buildVisibleProductsIndex(BASE_SALES);
    localStorage.removeItem(ADMIN_BASE_KEY);
    localStorage.removeItem(ADMIN_IMPORTED_FILES_KEY);
    localStorage.removeItem(ADMIN_PERCENTAGES_KEY);
    localStorage.removeItem(ADMIN_DAY_LABELS_KEY);
    adminDayPercentages = createDefaultAdminPercentages();
    adminDayLabels = createDefaultAdminDayLabels();
    refreshDeliveryDaysConfig();

    if ($.adminFileInput) {
      $.adminFileInput.value = "";
    }

    if ($.adminFileName) {
      $.adminFileName.textContent = "Nenhuma planilha selecionada.";
    }

    populateFilters();
    populateAdminStoreFilter();
    populateAdminDateFilter();
    renderAdminImportedFiles();
    renderAll();
    await refreshAdminSummary();
    await renderizarTabelaADM();
    showStatus("Planilha excluída com sucesso. Os dados ligados a ela foram removidos.");
  } catch (error) {
    console.error(error);
    showStatus("Não foi possível excluir a planilha agora.", true);
  }
}

async function getAdminSummaryRows() {
  const localSubmissions = Object.values(readJson(STORAGE_KEY));
  const cloudSubmissions = cloud?.listAll ? await cloud.listAll() : [];
  const submissions = mergeSubmissions(localSubmissions, cloudSubmissions);
  const rows = [];

  Object.keys(BASE_SALES)
    .sort((a, b) => getDisplayStoreName(a).localeCompare(getDisplayStoreName(b), "pt-BR"))
    .forEach((storeKey) => {
      DELIVERY_DAYS.forEach((day) => {
        const totalVendido = PRODUCT_ORDER.reduce((sum, product) => {
          return sum + Number(BASE_SALES[storeKey]?.[day.key]?.[product] || 0);
        }, 0);

        const totalSoFolhas = PRODUCT_ORDER.reduce((sum, product) => {
          return sum + getSoFolhasSuggestion(Number(BASE_SALES[storeKey]?.[day.key]?.[product] || 0), day.key);
        }, 0);

        const submission = submissions.find((item) =>
          slugify(item.loja) === slugify(storeKey) && (Array.isArray(item.dia) ? item.dia.includes(day.key) : String(item.dia) === day.key)
        );

        if (totalVendido === 0 && !submission) return;

        rows.push({
          loja: getDisplayStoreName(storeKey),
          dia: day.label,
          totalVendido,
          totalSoFolhas,
          totalLoja: submission?.totalLoja ?? "",
          responsavel: submission?.responsavel || "-",
          updatedAt: submission?.updatedAt || submission?.updatedAtServer || "",
        });
      });
    });

  return rows;
}

async function getAdminFilledRows() {
  const localSubmissions = Object.values(readJson(STORAGE_KEY));
  const cloudSubmissions = cloud?.listAll ? await cloud.listAll() : [];
  const submissions = mergeSubmissions(localSubmissions, cloudSubmissions)
    .sort((a, b) => {
      const storeCompare = String(a.lojaExibicao || a.loja || "").localeCompare(String(b.lojaExibicao || b.loja || ""), "pt-BR");
      if (storeCompare !== 0) return storeCompare;
      return String(Array.isArray(a.dia) ? a.dia.join("+") : a.dia || "").localeCompare(String(Array.isArray(b.dia) ? b.dia.join("+") : b.dia || ""));
    });

  const rows = submissions.flatMap((submission) => {
    const storeLabel = submission.lojaExibicao || getDisplayStoreName(submission.loja) || submission.loja || "-";
    const diaArray = Array.isArray(submission.dia) ? submission.dia : [submission.dia || ""];
    const dayLabel = diaArray.map((dayKey) => getDayLabel(dayKey) || dayKey || "-").join(" + ");
    const dayKeyText = diaArray.filter(Boolean).join("+");
    const submissionId = submission.id || `${slugify(submission.loja)}__${dayKeyText}`;
    return (submission.items || []).map((item) => ({
      loja: storeLabel,
      lojaKey: submission.loja || "",
      dia: dayLabel,
      diaKey: dayKeyText,
      diaArray,
      responsavel: submission.responsavel || "-",
      produto: item.product || "-",
      baseSale: Number(item.baseSale || 0),
      suggested: Number(item.suggested || 0),
      storeSuggestion: Number(item.storeSuggestion || 0),
      observation: item.observation || "",
      updatedAt: submission.updatedAt || submission.updatedAtServer || "",
      submissionId,
    }));
  });

  return rows.sort((a, b) => {
    const storeCompare = String(a.loja || "").localeCompare(String(b.loja || ""), "pt-BR");
    if (storeCompare !== 0) return storeCompare;
    const dayCompare = String(a.dia || "").localeCompare(String(b.dia || ""), "pt-BR");
    if (dayCompare !== 0) return dayCompare;
    return String(a.produto || "").localeCompare(String(b.produto || ""), "pt-BR");
  });
}

