function filterAdminFilledRows(rows) {
  const selectedStore = $.adminStoreFilter?.value || "";
  const selectedDate = $.adminDateFilter?.value || "";

  return rows.filter((row) => {
    const storeOk = !selectedStore || String(row.loja || "") === selectedStore;
    const dateOk = !selectedDate || (Array.isArray(row.diaArray) ? row.diaArray.includes(selectedDate) : String(row.diaKey || "") === selectedDate);
    return storeOk && dateOk;
  });
}

function getAdminFilledFilterLabel() {
  const filters = [];
  const selectedStore = $.adminStoreFilter?.value || "";
  const selectedDate = $.adminDateFilter?.value || "";

  if (selectedStore) {
    filters.push(`loja: ${selectedStore}`);
  }

  if (selectedDate) {
    const dayLabel = getDayLabel(selectedDate);
    filters.push(`data: ${dayLabel ? `${dayLabel} - ${formatDateKey(selectedDate)}` : formatDateKey(selectedDate)}`);
  }

  return filters.length ? ` • filtro: ${filters.join(" • ")}` : "";
}

function refreshAdminDateProgress(rows) {
  if (!$.adminDateProgress) return;

  const selectedDate = $.adminDateFilter?.value || "";
  if (!selectedDate) {
    $.adminDateProgress.textContent = "";
    return;
  }

  const totalStores = Object.keys(BASE_SALES).length;
  const filledStores = new Set(
    (rows || [])
      .filter((row) => Array.isArray(row.diaArray) ? row.diaArray.includes(selectedDate) : String(row.diaKey || "") === selectedDate)
      .map((row) => row.loja)
  ).size;
  const pendingStores = Math.max(totalStores - filledStores, 0);
  const filledPercent = totalStores ? Math.round((filledStores / totalStores) * 100) : 0;
  const dayLabel = getDayLabel(selectedDate);
  const dayText = dayLabel ? `${dayLabel} - ${formatDateKey(selectedDate)}` : formatDateKey(selectedDate);

  $.adminDateProgress.textContent = `Percentual da data ${dayText}: ${filledStores} de ${totalStores} lojas já preencheram (${filledPercent}%). Faltam ${pendingStores} lojas.`;
}

function refreshAdminProgress(rows) {
  const totalStores = Object.keys(BASE_SALES).length;
  const filledStores = new Set((rows || []).filter((row) => row.responsavel && row.responsavel !== "-").map((row) => row.loja)).size;
  const pendingStores = Math.max(totalStores - filledStores, 0);
  const filledPercent = totalStores ? Math.round((filledStores / totalStores) * 100) : 0;
  const pendingPercent = totalStores ? Math.max(100 - filledPercent, 0) : 0;

  if ($.adminProgressMeta) {
    $.adminProgressMeta.textContent = `${filledStores} de ${totalStores} lojas já preencheram`;
  }

  if ($.adminProgressFilledBar) {
    $.adminProgressFilledBar.style.width = `${filledPercent}%`;
  }

  if ($.adminProgressPendingBar) {
    $.adminProgressPendingBar.style.width = `${pendingPercent}%`;
  }

  if ($.adminProgressFilledText) {
    $.adminProgressFilledText.textContent = `Preenchidas: ${filledStores} (${filledPercent}%)`;
  }

  if ($.adminProgressPendingText) {
    $.adminProgressPendingText.textContent = `Pendentes: ${pendingStores} (${pendingPercent}%)`;
  }
}

