function downloadTextFile(content, fileName, mimeType) {
  const blob = new Blob([content], { type: mimeType });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = fileName;
  document.body.appendChild(link);
  link.click();
  link.remove();
  setTimeout(() => URL.revokeObjectURL(url), 1000);
}

function escapeCsvValue(value) {
  const text = String(value ?? "");
  if (text.includes('"') || text.includes(';') || text.includes('\n')) {
    return `"${text.replaceAll('"', '""')}"`;
  }
  return text;
}

function exportRowsAsCsv(rows, fileName) {
  const safeRows = rows.length ? rows : [{ mensagem: "Nenhum dado disponível para exportação." }];
  const headers = Object.keys(safeRows[0]);
  const lines = [headers.join(";")]
    .concat(safeRows.map((row) => headers.map((header) => escapeCsvValue(row[header])).join(";")));
  downloadTextFile(`﻿${lines.join("\n")}`, fileName.replace(/\.xlsx$/i, ".csv"), "text/csv;charset=utf-8;");
}

function exportWorkbook(sheetName, rows, fileName) {
  const safeRows = rows.length ? rows : [{ mensagem: "Nenhum dado disponível para exportação." }];

  if (window.XLSX?.utils?.book_new) {
    const workbook = window.XLSX.utils.book_new();
    const worksheet = window.XLSX.utils.json_to_sheet(safeRows);
    window.XLSX.utils.book_append_sheet(workbook, worksheet, sheetName);
    window.XLSX.writeFile(workbook, fileName);
    return;
  }

  exportRowsAsCsv(safeRows, fileName);
}

